下载源码# mkdir LLVM cd LLVM wget https://github.com/llvm/llvm-project/archive/llvmorg-11.0.0.zip unzip llvmorg-11.0.0.zip编写编译脚本# 在 LLVM 目录下,创建一个build.sh文件,拷贝下面内容 #!/usr/bin/env bash set -e set -o pipefail set -u ROOT_DIR=`pwd` SOURCE_CODE_DIR=$ROOT_DIR/llvm-project-llvmorg-11.0.0 BUILD_DIR=$ROOT_DIR/build_dir LLVM_BUILD_DIR=$BUILD_DIR/build_llvm LLVM_OUT_DIR=$BUILD_DIR/build_llvm_out CLANG_BUILD_DIR=$BUILD_DIR/build_clang CLANG_OUT_DIR=$BUILD_DIR/build_clang_out XCODE_BUILD_DIR=$BUILD_DIR/build_xcode XCODE_OUT_DIR=$BUILD_DIR/build_xcode_out function build_llvm() { echo &#34;generate llvm ninja build config ...&#34; cd $LLVM_BUILD_DIR cmake -G &#34;Ninja&#34; \ -DCMAKE_OSX_DEPLOYMENT_TARGET=&#34;10.14&#34; \ -DCMAKE_OSX_SYSROOT=&#34;macosx&#34; \ -DCMAKE_OSX_ARCHITECTURES=&#39;x86_64&#39; \ -DLLVM_TARGETS_TO_BUILD=&#34;X86&#34; \ -DCMAKE_BUILD_TYPE=Release \ -DCMAKE_INSTALL_PREFIX=$LLVM_OUT_DIR \ $SOURCE_CODE_DIR/llvm echo &#34;ninja build llvm ...&#34; ninja install } function build_clang() { echo &#34;generate clang ninja build config ...&#34; cd $CLANG_BUILD_DIR cmake -G &#34;Ninja&#34; \ -DCMAKE_PREFIX_PATH=$LLVM_OUT_DIR/lib/cmake/llvm \ -DCMAKE_OSX_DEPLOYMENT_TARGET=&#34;10.14&#34; \ -DCMAKE_OSX_SYSROOT=&#34;macosx&#34; \ -DCMAKE_OSX_ARCHITECTURES=&#39;x86_64&#39; \ -DLLVM_TARGETS_TO_BUILD=&#34;X86&#34; \ -DCMAKE_BUILD_TYPE=Release \ -DCMAKE_INSTALL_PREFIX=$CLANG_OUT_DIR \ $SOURCE_CODE_DIR/clang echo &#34;ninja build clang ...&#34; ninja install } function generate_xcode_project() { cd $XCODE_BUILD_DIR cmake -G &#34;Xcode&#34; \ -DCMAKE_OSX_DEPLOYMENT_TARGET=&#34;10.14&#34; \ -DCMAKE_OSX_SYSROOT=&#34;macosx&#34; \ -DCMAKE_OSX_ARCHITECTURES=&#39;x86_64&#39; \ -DLLVM_TARGETS_TO_BUILD=&#34;X86&#34; \ -DCMAKE_BUILD_TYPE=Release \ -DCMAKE_INSTALL_PREFIX=$XCODE_OUT_DIR \ $SOURCE_CODE_DIR/llvm } function clear_build() { echo &#34;clear build dir&#34; rm -rf $BUILD_DIR } function usage() { echo &#34;Usage:&#34; echo &#34;build.sh -b -x&#34; echo &#34;Description:&#34; echo &#34;-b, build llvm and clang&#34; echo &#34;-x, generate xcode project&#34; echo &#34;-c, clear build dir&#34; exit 0 } function onCtrlC () { clear_build exit 0 } BUILD_FLAG=0 GENERATE_XCODE_FLAG=0 CLEAR_BUILD_FLAG=0 while getopts &#39;hbxc&#39; OPT; do case $OPT in b) BUILD_FLAG=1;; x) GENERATE_XCODE_FLAG=1;; c) CLEAR_BUILD_FLAG=1;; h) usage;; ?) usage;; esac done if [[ $CLEAR_BUILD_FLAG == 1 ]]; then clear_build fi if [[ $BUILD_FLAG == 1 ]]; then # trap &#39;onCtrlC&#39; INT startTime_s=`date +%s` if [[ $GENERATE_XCODE_FLAG == 1 ]]; then mkdir -p $XCODE_BUILD_DIR generate_xcode_project else mkdir -p $LLVM_BUILD_DIR $CLANG_BUILD_DIR build_llvm build_clang fi endTime_s=`date +%s` sumTime=$[ $endTime_s - $startTime_s ] echo &#34;开始: $(date -r $startTime_s +%Y%m%d-%H:%M:%S)&#34; echo &#34;结束: $(date -r $endTime_s +%Y%m%d-%H:%M:%S)&#34; hour=$[ $sumTime / 3600 ] minutes=$[ ($sumTime - ($hour * 3600)) / 60 ] seconds=$[ ($sumTime - ($hour * 3600)) % 60 ] echo &#34;耗时：$hour:$minutes:$seconds&#34; fi创建PASS工程# 进入llvm-project-llvmorg-11.0.0/llvm/lib/Transforms 目录 将 Hello 目录拷贝一份,并重命名为 FunctionCallTime 在 llvm-project-llvmorg-11.0.0/llvm/lib/Transforms/CMakeLists.txt 后面追加一行 add_subdirectory(FunctionCallTime) 在 llvm-project-llvmorg-11.0.0/llvm/lib/Transforms/LLVMBuild.txt subdirectories 后面追加 FunctionCallTime 修改 FunctionCallTime/CMakeLists.txt 为下面内容 # If we don&#39;t need RTTI or EH, there&#39;s no reason to export anything # from the hello plugin. if( NOT LLVM_REQUIRES_RTTI ) if( NOT LLVM_REQUIRES_EH ) set(LLVM_EXPORTED_SYMBOL_FILE ${CMAKE_CURRENT_SOURCE_DIR}/FunctionCallTime.exports) endif() endif() if(WIN32 OR CYGWIN) set(LLVM_LINK_COMPONENTS Core Support) endif() set(LLVM_LINK_COMPONENTS Demangle) add_llvm_library( LLVMFunctionCallTime MODULE BUILDTREE_ONLY FunctionCallTime.cpp DEPENDS intrinsics_gen PLUGIN_TOOL opt ) 将 Hello.cpp 重命名为 FunctionCallTime.cpp, Hello.exports 重命名为 FunctionCallTime.exports 将FunctionCallTime.cpp 内容替换为下面 // // function_call_time.cpp // function-call-time // // Created by king on 2020/12/18. // #include &lt;iostream&gt; #include &#34;llvm/ADT/Statistic.h&#34; #include &#34;llvm/Demangle/Demangle.h&#34; #include &#34;llvm/IR/BasicBlock.h&#34; #include &#34;llvm/IR/Constants.h&#34; #include &#34;llvm/IR/Function.h&#34; #include &#34;llvm/IR/IRBuilder.h&#34; #include &#34;llvm/IR/Instruction.h&#34; #include &#34;llvm/IR/Instructions.h&#34; #include &#34;llvm/IR/LegacyPassManager.h&#34; #include &#34;llvm/IR/Module.h&#34; #include &#34;llvm/IR/Value.h&#34; #include &#34;llvm/Pass.h&#34; #include &#34;llvm/Support/raw_ostream.h&#34; #include &#34;llvm/Transforms/IPO/PassManagerBuilder.h&#34; using namespace llvm; namespace { struct FunctionCallTimePass : public FunctionPass { static char ID; static StringRef InsertFuncNamePrefix; static StringRef BeginFuncName; static StringRef EndFuncName; FunctionCallTimePass() : FunctionPass(ID) {} bool runOnFunction(Function &amp;F) override { if (F.empty()) { return false; } std::string annotation = readAnnotate(&amp;F); auto funcName = F.getName(); // 可以通过 __attribute__((__annotate__((&#34;ignore_appletrace&#34;)))) // 忽略当前函数 if (annotation.length() &gt; 0 &amp;&amp; StringRef(annotation).contains(&#34;ignore_appletrace&#34;)) { errs() &lt;&lt; &#34;function-call-time: &#34; &lt;&lt; funcName &lt;&lt; &#34; 忽略 annotation&#34; &lt;&lt; &#34;
&#34;; return false; } // Objective-C 方法前面有 \x01 if (funcName.front() == &#39;\x01&#39;) { funcName = funcName.drop_front(); } if (funcName.startswith(&#34;__Z&#34;) || funcName.startswith(&#34;_Z&#34;)) { // C++ 函数 std::string str = funcName.str(); std::string demangled = demangle(str); funcName = StringRef(demangled); } // 将统计代码调用过滤掉 if (funcName.startswith(&#34;appletrace&#34;)) { return false; } // 如果是插桩的函数直接跳过 if (F.getName().startswith(FunctionCallTimePass::InsertFuncNamePrefix)) { return false; } // 只统计 Objective-C 方法调用 if (funcName.startswith(&#34;+[&#34;) || funcName.startswith(&#34;-[&#34;)) { // 2. 插入开始 if (!insertBeginInst(F)) { return false; } // 3. 插入结束 insertEndInst(F); return false; } return false; } private: std::string readAnnotate(Function *f) { std::string annotation = &#34;&#34;; // Get annotation variable GlobalVariable *glob = f-&gt;getParent()-&gt;getGlobalVariable(&#34;llvm.global.annotations&#34;); if (glob != NULL) { // Get the array if (ConstantArray *ca = dyn_cast&lt;ConstantArray&gt;(glob-&gt;getInitializer())) { for (unsigned i = 0; i &lt; ca-&gt;getNumOperands(); ++i) { // Get the struct if (ConstantStruct *structAn = dyn_cast&lt;ConstantStruct&gt;(ca-&gt;getOperand(i))) { if (ConstantExpr *expr = dyn_cast&lt;ConstantExpr&gt;(structAn-&gt;getOperand(0))) { // If it&#39;s a bitcast we can check if the annotation is concerning // the current function if (expr-&gt;getOpcode() == Instruction::BitCast &amp;&amp; expr-&gt;getOperand(0) == f) { ConstantExpr *note = cast&lt;ConstantExpr&gt;(structAn-&gt;getOperand(1)); // If it&#39;s a GetElementPtr, that means we found the variable // containing the annotations if (note-&gt;getOpcode() == Instruction::GetElementPtr) { if (GlobalVariable *annoteStr = dyn_cast&lt;GlobalVariable&gt;(note-&gt;getOperand(0))) { if (ConstantDataSequential *data = dyn_cast&lt;ConstantDataSequential&gt;( annoteStr-&gt;getInitializer())) { if (data-&gt;isString()) { annotation += data-&gt;getAsString().lower() + &#34; &#34;; } } } } } } } } } } return annotation; } bool insertBeginInst(Function &amp;F) { // 0.函数最开始的BasicBlock LLVMContext &amp;context = F.getParent()-&gt;getContext(); BasicBlock &amp;BB = F.getEntryBlock(); // 1. 获取要插入的函数 FunctionCallee beginFun = F.getParent()-&gt;getOrInsertFunction( FunctionCallTimePass::BeginFuncName, FunctionType::get(Type::getVoidTy(context), {Type::getInt8PtrTy(context)}, false)); errs() &lt;&lt; &#34;function-call-time: &#34; &lt;&lt; BB.getParent()-&gt;getName() &lt;&lt; &#34; begin
&#34;; // 2. 构造函数 CallInst *inst = nullptr; IRBuilder&lt;&gt; builder(&amp;BB); IRBuilder&lt;&gt; callBuilder(context); Value *name = builder.CreateGlobalStringPtr(BB.getParent()-&gt;getName()); inst = callBuilder.CreateCall(beginFun, {name}); if (!inst) { llvm::errs() &lt;&lt; &#34;Create First CallInst Failed
&#34;; return false; } // 3. 获取函数开始的第一条指令 Instruction *beginInst = dyn_cast&lt;Instruction&gt;(BB.begin()); // 4. 将inst插入 inst-&gt;insertBefore(beginInst); return true; } void insertEndInst(Function &amp;F) { LLVMContext &amp;context = F.getParent()-&gt;getContext(); for (Function::iterator I = F.begin(), E = F.end(); I != E; ++I) { // 函数结尾的BasicBlock BasicBlock &amp;BB = *I; for (BasicBlock::iterator I = BB.begin(), E = BB.end(); I != E; ++I) { ReturnInst *IST = dyn_cast&lt;ReturnInst&gt;(I); if (!IST) continue; // end_func 类型 FunctionType *endFuncType = FunctionType::get( Type::getVoidTy(context), {Type::getInt8PtrTy(context)}, false); // end_func FunctionCallee endFunc = BB.getModule()-&gt;getOrInsertFunction( FunctionCallTimePass::EndFuncName, endFuncType); // 构造end_func IRBuilder&lt;&gt; builder(&amp;BB); IRBuilder&lt;&gt; callBuilder(context); Value *name = builder.CreateGlobalStringPtr(BB.getParent()-&gt;getName()); CallInst *endCI = callBuilder.CreateCall(endFunc, {name}); // 插入end_func(struction) endCI-&gt;insertBefore(IST); errs() &lt;&lt; &#34;function-call-time: &#34; &lt;&lt; BB.getParent()-&gt;getName() &lt;&lt; &#34; end
&#34;; } } } }; } // namespace char FunctionCallTimePass::ID = 0; StringRef FunctionCallTimePass::InsertFuncNamePrefix = &#34;_kk_APT&#34;; StringRef FunctionCallTimePass::BeginFuncName = &#34;_kk_APTBeginSection&#34;; StringRef FunctionCallTimePass::EndFuncName = &#34;_kk_APTEndSection&#34;; // 注册给 opt // opt -load LLVMFunctionCallTime.dylib -function-call-time xx.bc static RegisterPass&lt;FunctionCallTimePass&gt; X(&#34;function-call-time&#34;, &#34;Function calls take time to collect&#34;, false, false); // 注册给 clang 通过 -Xclang -load -Xclang LLVMFunctionCallTime.dylib static RegisterStandardPasses Y(PassManagerBuilder::EP_EarlyAsPossible, [](const PassManagerBuilder &amp;Builder, legacy::PassManagerBase &amp;PM) { PM.add(new FunctionCallTimePass()); });创建Xcode工程# 需要安装cmake 进入 LLVM 目录下执行 chmod +x ./build.sh # 只需要执行一次 ./build.sh -b -x 执行成功后,会在LLVM目录下生成build_dir目录 build_dir └── build_xcode ├── CMakeCache.txt ├── CMakeFiles ├── CMakeScripts ├── CPackConfig.cmake ├── CPackSourceConfig.cmake ├── Debug ├── LLVM.xcodeproj ├── LLVMBuild.cmake ├── MinSizeRel ├── RelWithDebInfo ├── Release ├── benchmarks ├── build ├── cmake ├── cmake_install.cmake ├── docs ├── examples ├── include ├── lib ├── llvm.spec ├── projects ├── runtimes ├── test ├── tools ├── unittests └── utils 打开 LLVM.xcodeproj, 会提示创建scheme, 可以选择自动,也可以选择手动, Pass scheme 为LLVMFunctionCallTime FunctionCallTime Pass target 在 Loadable modules 下面 选择LLVMFunctionCallTime command + b 进行编译 默认是Debug模式,所以LLVMFunctionCallTime.dylib产物在build_dir/build_xcode/Debug/lib/LLVMFunctionCallTime.dylib 使用 Pass# 由于Xcode内置的clang,不支持加载自定义插件,所以直接从LLVM Project Github 仓库下载编译好的 由于开始下载的源码为LLVM 11.0.0, 所以为了一致也是下载相同的版本 wget https://github.com/llvm/llvm-project/releases/download/llvmorg-11.0.0/clang+llvm-11.0.0-x86_64-apple-darwin.tar.xz mkdir -p ./clang-11.0.0 tar xf clang+llvm-11.0.0-x86_64-apple-darwin.tar.xz -C ./clang-11.0.0 --strip-components 1 下载 everettjf/AppleTrace 将 appletrace.h appletrace.mm 拖入你的工程中 将APTBeginSection APTEndSection APTSyncWait 修改为 _kk_APTBeginSection _kk_APTEndSection _kk_APTSyncWait,为了便于区分在Pass里面指定了 _kk_APT前缀 将appletrace.mm 中WriteSection 改为如下 void WriteSection(const char *name, const char *ph) { pthread_t thread = pthread_self(); __uint64_t thread_id = 0; pthread_threadid_np(thread, &amp;thread_id); uint64_t time = mach_absolute_time() * timeinfo_.numer / timeinfo_.denom; uint64_t elapsed = (time - begin_) / 1000.0; if (main_thread_id == 0 &amp;&amp; pthread_main_np() != 0) { main_thread_id = thread_id; } if (main_thread_id == thread_id) { thread_id = 0; // just make main thread id zero } // 通过 llvm pass 插桩传递过来的 name 最前有个 \0x1 所以需要特殊处理下 // 当然也可以直接在 pass 中处理好 NSString *str = nil; if (name[0] == &#39;\x01&#39;) { str = [NSString stringWithFormat:@&#34;{\&#34;name\&#34;:\&#34;%s\&#34;,\&#34;cat\&#34;:\&#34;catname\&#34;,\&#34;ph\&#34;:\&#34;%s\&#34;,\&#34;pid\&#34;:666,\&#34;tid\&#34;:%llu,\&#34;ts\&#34;:%llu}&#34;, name + 1, ph, thread_id, elapsed]; } else { str = [NSString stringWithFormat:@&#34;{\&#34;name\&#34;:\&#34;%s\&#34;,\&#34;cat\&#34;:\&#34;catname\&#34;,\&#34;ph\&#34;:\&#34;%s\&#34;,\&#34;pid\&#34;:666,\&#34;tid\&#34;:%llu,\&#34;ts\&#34;:%llu}&#34;, name, ph, thread_id, elapsed]; } dispatch_async(queue_, ^{ log_.AddLine(str.UTF8String); }); } 在你的工程中创建一个xcconfig 文件,内容如下 // // Config.xcconfig // PageLinkDemo // // Created by king on 2020/12/18. // // Configuration settings file format documentation can be found at: // https://help.apple.com/xcode/#/dev745c5c974 LLVM_DIR = $HOME/Documents/LLVM # 修改为在你本机的实际路径 PASS_DYLIB = $(LLVM_DIR)/build_dir/build_xcode/Debug/lib/LLVMFunctionCallTime.dylib OTHER_CFLAGS = $(inherited) -Xclang -load -Xclang $(PASS_DYLIB) OTHER_CPLUSPLUSFLAGS = $(inherited) -Xclang -load -Xclang $(PASS_DYLIB) COMPILER_INDEX_STORE_ENABLE = NO CC = $(LLVM_DIR)/clang-11.0.0/bin/clang CXX = $(LLVM_DIR)clang-11.0.0/bin/clang++ 修改工程配置 然后进行编译,如果没有错误,则会在Xcode编译日志中可以看到相关日志,如下图 由于qmuidemo 依赖了 qmui 子工程,所以我将 appletrace.h appletrace.mm 放到了 qmui工程中,这样主工程和子工程则都能进行插桩 运行你的项目后,会在Xcode控制台看到如下输出 2020-12-20 14:49:32.530027+0800 qmuidemo[25684:1347559] log path = /Users/king/Library/Developer/CoreSimulator/Devices/71211D11-6169-4508-BBD8-B38958350C8F/data/Containers/Data/Application/46E933FE-D962-4355-9E0D-F8CBA44ABFA7/Library/appletracedata/trace.appletrace使用everettjf/AppleTrace生成火焰图# 通过上面输出的log path,将appletracedata目录拷贝到 下载的everettjf/AppleTrace中 将下载的everettjf/AppleTrace merge.py 中 run函数的while循环外面添加如下代码 self.output.seek(-2, os.SEEK_END) self.output.truncate() self.output.write(&#39;
]&#39;) 合并appletracedata目录下所有文件内容,输出为JSON文件 python merge.py -d ./appletracedata 下载依赖 sh get_catapult.sh 生成火焰图 HTML 文件 # 生成 python catapult/tracing/bin/trace2html appletracedata/trace.json --output=appletracedata/trace.html # 打开预览 open trace.html 预览 QMUIDemo 火焰图 使用Xcode 调试 Pass# 需要通过opt调试 首先需要先编译好Pass 生成IR文件 clang -x objective-c++ -isysroot $(xcrun --sdk macosx --show-sdk-path) -S -emit-llvm -c xxx.m -o xx.ll 切换为opt scheme, 选择Edit Scheme 设置 opt的启动参数,如下 然后运行 opt, 由于opt依赖很多,所有需要编译很长时间,不过如果你是40万的Mac Pro,那么可能只需要几秒或者十几秒 这样就可以直接在Pass源码中下断点 LLVMFunctionCallTimePass 源码 参考# Writing an LLVM Pass Clang 插件统计方法耗时

通过Lookin查看视图层级可得知:# 首页是一个导航栏控制器, 其 rootViewController 为 AWEFeedRootViewController AWEFeedContainerViewController 为视频列表的控制器, 同时 AWEFeedContainerViewController 做为 AWEFeedRootViewController 的 childViewController AWECommentListViewController 为评论弹层, AWECommentListViewController 并未采用 addChildViewController 方式加入 AWEFeedContainerViewController 作为其 childViewController, 而是直接将 AWECommentListViewController.view 添加到 AWEFeedRootViewController.view AWECommentListViewController 的视图层级如下:# baseView effectView 为 UIVisualEffectView 实现模糊效果 headerView tableView keyboardMaskView 当键盘弹出时,才显示,用于实现点击上半部分关闭键盘 commentInputView 底部输入框 抖音评论列表有以下效果:# 无评论数据时,整个 baseView 区域可以通过手势往下滑动以关闭列表 有评论数据时,下滑tableView到顶时继续往下滑动,则会让baseView和commentInputView同步联动往下滑 同时还有两个细节个人认为没有处理好: 当往下联动后再往上滑动无法触发tableView继续往上滑动 当tableView已经往上滑动了一部分后,从headerView区域无法触发滑动,只能先通过tableView触发,然后激活联动处理 接下来通过逆向分析得知:# 通过上面分析的视图层级,找到baseView, 发现baseView自身被添加了一个UIPanGestureRecognizer UIPanGestureRecognizer 的 target 为 AWECommentListViewController UIPanGestureRecognizer 的 action 为 AWECommentListViewController 的 selfPanned: UIPanGestureRecognizer 的 delegate 为 AWECommentListViewController 大致确定了整个联动处理是依靠baseView的手势和tableView自身的手势共同完成 iPhone:~ root# cycript -p Aweme cy# UIApp.keyWindow.rootViewController #&#34;&lt;AWETabBarController: 0x116283600&gt;&#34; cy# [#0x116a59520 subviews] @[#&#34;&lt;UIView: 0x115e3f7d0; frame = (0 0; 375 667); autoresize = W+H; layer = &lt;CALayer: 0x282b1a7a0&gt;&gt;&#34;,#&#34;&lt;UIView: 0x119063140; frame = (0 0; 375 667); autoresize = W+H; gestureRecognizers = &lt;NSArray: 0x2827722e0&gt;; layer = &lt;CALayer: 0x282af3ac0&gt;&gt;&#34;] cy# [#0x119063140 subviews] @[#&#34;&lt;UIView: 0x11f16f720; frame = (0 180; 375 487); gestureRecognizers = &lt;NSArray: 0x282773c60&gt;; layer = &lt;CALayer: 0x282a8fd00&gt;&gt;&#34;,#&#34;&lt;UIView: 0x11f1d60d0; frame = (0 667; 375 200); layer = &lt;CALayer: 0x282aa3b20&gt;&gt;&#34;,#&#34;&lt;UIView: 0x11f1f3370; frame = (0 0; 375 667); alpha = 0; gestureRecognizers = &lt;NSArray: 0x282755860&gt;; layer = &lt;CALayer: 0x282c6d720&gt;&gt;&#34;,#&#34;&lt;AWECommentListInputView: 0x11f1f0110; frame = (0 618; 375 49); gestureRecognizers = &lt;NSArray: 0x282765380&gt;; layer = &lt;CALayer: 0x282bc2080&gt;&gt;&#34;] .... .... cy# [#0x11f16f720 gestureRecognizers] @[#&#34;&lt;UIPanGestureRecognizer: 0x12175a1c0; state = Possible; view = &lt;UIView 0x11f16f720&gt;; targets= &lt;(
 \&#34;(action=selfPanned:, target=&lt;AWECommentListViewController 0x1163bd400&gt;)\&#34;,
